const input = $json || {};

const normalize = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const lower = (value) => normalize(value).toLowerCase();

const tenant_id = normalize(input.tenant_id);
const trace_id = normalize(input.trace_id) || (globalThis.crypto?.randomUUID?.() || `trace_${Date.now()}`);
const session_id = normalize(input.session_id) || `session_${Date.now()}`;

const user_request = normalize(input.user_request);
const business_type = lower(input.business_type || 'professional');
const nome_attivita = normalize(input.nome_attivita);
const indirizzo = normalize(input.indirizzo);
const orari_apertura = normalize(input.orari_apertura);
const current_date = normalize(input.current_date);
const current_time = normalize(input.current_time);

const requestLower = user_request.toLowerCase();

const knownCities = [
  'rimini',
  'riccione',
  'cattolica',
  'misano adriatico',
  'misano',
  'bellaria',
  'igea marina',
  'santarcangelo',
  'cesenatico',
  'pesaro',
  'ravenna'
];

function titleCase(value) {
  return normalize(value)
    .split(' ')
    .filter(Boolean)
    .map(part => part.charAt(0).toUpperCase() + part.slice(1).toLowerCase())
    .join(' ');
}

function extractCityFromRequest(text) {
  const normalized = lower(text);
  const found = knownCities.find(city => normalized.includes(city));
  return found ? titleCase(found) : '';
}

function extractCityFromAddress(address) {
  const raw = normalize(address);
  if (!raw) return '';

  let match = raw.match(/-\s*\d{5}\s+([^()\-]+?)\s*\([A-Z]{2}\)\s*$/i);
  if (match) return titleCase(match[1]);

  match = raw.match(/\b\d{5}\s+([^()\-]+?)\s*(?:\([A-Z]{2}\))?\s*$/i);
  if (match) return titleCase(match[1]);

  const found = knownCities.find(city => lower(raw).includes(city));
  if (found) return titleCase(found);

  const parts = raw.split(',').map(s => normalize(s)).filter(Boolean);
  if (parts.length > 0) {
    const last = parts[parts.length - 1].replace(/\([A-Z]{2}\)/g, '').trim();
    if (last) return titleCase(last);
  }

  return '';
}

function detectTimeContext(text) {
  const t = lower(text);

  if (/questo weekend|fine settimana|questo fine settimana/.test(t)) return 'weekend';
  if (/stasera|questa sera/.test(t)) return 'stasera';
  if (/dopo cena/.test(t)) return 'dopo_cena';
  if (/stanotte|questa notte/.test(t)) return 'stanotte';
  if (/\boggi\b/.test(t)) return 'oggi';
  if (/\bdomani\b/.test(t)) return 'domani';
  if (/ora|adesso|aperto ora/.test(t)) return 'ora';
  return '';
}

function detectQueryType(text) {
  const t = lower(text);

  if (/farmacia.*di turno|di turno.*farmacia/.test(t)) return 'pharmacy_on_duty';
  if (/farmacia.*(aperta|aperto|ora|adesso)|aperta ora.*farmacia/.test(t)) return 'pharmacy_open_now';
  if (/guardia medica|continuit[aà] assistenziale/.test(t)) return 'medical_guard';
  if (/pronto soccorso/.test(t)) return 'emergency_room';
  if (/taxi|cab/.test(t)) return 'taxi';
  if (/parcheggio|parcheggi/.test(t)) return 'parking';
  if (/tabaccaio|tabacchi|sigarette|bollo/.test(t)) return 'tobacco';
  if (/sexy shop|sex shop/.test(t)) return 'sexy_shop';
  if (/supermercato|market|alimentari/.test(t)) return 'supermarket';
  if (/spiaggia|lido|stabilimento balneare/.test(t)) return 'beach';
  if (/discoteca|discoteche|club|locale notturno/.test(t)) return 'nightlife';
  if (/bar|pub|cocktail bar|aperitivo/.test(t)) return 'bar';
  if (/evento|eventi|festival|concerto|concerti|cosa posso fare|cosa fare|cosa c['’]e|cosa cè|serata|serate/.test(t)) return 'events';
  return 'poi_generic';
}

const query_type = detectQueryType(user_request);
const time_context = detectTimeContext(user_request);

const city_from_request = extractCityFromRequest(user_request);
const city_from_address = extractCityFromAddress(indirizzo);
const resolved_location = city_from_request || city_from_address;

const is_time_sensitive = [
  'pharmacy_on_duty',
  'pharmacy_open_now',
  'medical_guard',
  'emergency_room'
].includes(query_type) || ['ora', 'oggi', 'stasera', 'stanotte'].includes(time_context);

let needs_clarification = false;
let clarification_reason = '';

if (!user_request) {
  needs_clarification = true;
  clarification_reason = 'missing_request';
} else if (!resolved_location) {
  needs_clarification = true;
  clarification_reason = 'missing_location';
}

return [{
  json: {
    ...input,
    tenant_id,
    trace_id,
    session_id,
    user_request,
    business_type,
    nome_attivita,
    indirizzo,
    orari_apertura,
    current_date,
    current_time,
    query_type,
    time_context,
    is_time_sensitive,
    city_from_request,
    city_from_address,
    resolved_location,
    needs_clarification,
    clarification_reason,
    success: false,
    code: '',
    message: '',
    final_reply: ''
  }
}];

