    .replace(/che eventi/gi, ' ')
    .replace(/ci sono/gi, ' ')
    .replace(/in zona/gi, ' ')
    .replace(/qui vicino/gi, ' ')
    .replace(/vicino all['’]hotel/gi, ' ')
    .replace(/nei dintorni/gi, ' ')
    .replace(/[?.,!]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  return cleaned;
};

