        search_query = `concerti ${location} stasera`;
      } else {
        search_query = `concerti ${location}`;
      }
    } else if (wantsFestival) {
      if (timeContext === 'weekend') {
        search_query = `festival ${location} questo weekend`;
      } else {
        search_query = `festival ${location}`;
      }
