    search_query = `pronto soccorso ${location} indirizzo`;
    break;

  case 'taxi':
    search_query = `taxi ${location} numero telefono`;
    break;

  case 'parking':
    search_query = `parcheggio vicino hotel ${location}`;
    break;

  case 'tobacco':
    search_query = `tabacchi vicino hotel ${location}`;
    break;

  case 'sexy_shop':
    search_query = `sexy shop vicino hotel ${location}`;
    break;

  case 'supermarket':
    search_query = `supermercato vicino hotel ${location}`;
    break;

