      name: event.title || '',
      address: event.venue?.name || '',
      notes: event.date?.when || '',
      link: event.link || ''
    });
  }
}

const localPlaces = Array.isArray(response.local_results)
  ? response.local_results
  : Array.isArray(response.local_results?.places)
    ? response.local_results.places
    : [];

if (!normalizedResults.length && localPlaces.length) {
  for (const place of localPlaces.slice(0, 3)) {
    normalizedResults.push({
      name: place.title || place.name || '',
      address: place.address || '',
      notes: place.hours || place.description || '',
      link: place.website || place.directions || place.link || ''
    });
  }
}

if (!normalizedResults.length && Array.isArray(response.organic_results)) {
  for (const item of response.organic_results.slice(0, 5)) {
    const title = item.title || '';
    const snippet = item.snippet || '';
    const link = item.link || '';
    const displayed = item.displayed_link || '';
    const combined = `${title} ${snippet}`.toLowerCase();

    const relevant =
      query_type === 'pharmacy_on_duty'
        ? /farmacia|di turno|turno/.test(combined)
        : query_type === 'pharmacy_open_now'
          ? /farmacia|aperta|orari/.test(combined)
          : query_type === 'medical_guard'
            ? /guardia medica|continuit|medica/.test(combined)
            : query_type === 'emergency_room'
              ? /pronto soccorso|ospedale/.test(combined)
              : true;

    if (!relevant) continue;

    normalizedResults.push({
