    break;

  default:
    search_query = `${cleanedRequest || request} ${location}`.trim();
    break;
}

const max_results = ['pharmacy_on_duty', 'pharmacy_open_now', 'medical_guard', 'emergency_room'].includes(queryType) ? 5 : 3;

return [{
  json: {
    ...input,
    serp_engine,
    search_query,
    search_location: searchLocation,
    max_results
  }
}];

const response = $json || {};
const meta = $('Build Search Query').first().json;

const query_type = meta.query_type;
const resolved_location = meta.resolved_location;
const is_time_sensitive = Boolean(meta.is_time_sensitive);

const normalizedResults = [];

if (Array.isArray(response.events_results)) {
  for (const event of response.events_results.slice(0, 3)) {
    normalizedResults.push({
      name: event.title || '',
      address: event.venue?.name || '',
      notes: event.date?.when || '',
      link: event.link || ''
    });
  }
}

const localPlaces = Array.isArray(response.local_results)
  ? response.local_results
  : Array.isArray(response.local_results?.places)
    ? response.local_results.places
    : [];

if (!normalizedResults.length && localPlaces.length) {
  for (const place of localPlaces.slice(0, 3)) {
    normalizedResults.push({
      name: place.title || place.name || '',
      address: place.address || '',
      notes: place.hours || place.description || '',
      link: place.website || place.directions || place.link || ''
    });
  }
}

if (!normalizedResults.length && Array.isArray(response.organic_results)) {
  for (const item of response.organic_results.slice(0, 5)) {
    const title = item.title || '';
    const snippet = item.snippet || '';
    const link = item.link || '';
    const displayed = item.displayed_link || '';
    const combined = `${title} ${snippet}`.toLowerCase();

    const relevant =
      query_type === 'pharmacy_on_duty'
        ? /farmacia|di turno|turno/.test(combined)
        : query_type === 'pharmacy_open_now'
          ? /farmacia|aperta|orari/.test(combined)
          : query_type === 'medical_guard'
            ? /guardia medica|continuit|medica/.test(combined)
            : query_type === 'emergency_room'
              ? /pronto soccorso|ospedale/.test(combined)
              : true;

    if (!relevant) continue;

    normalizedResults.push({
      name: title,
      address: displayed,
      notes: snippet,
      link
    });

    if (normalizedResults.length >= 3) break;
  }
}

let success = normalizedResults.length > 0;
let code = success ? 'LOCAL_SEARCH_OK' : 'LOCAL_SEARCH_NO_CLEAR_RESULTS';
let message = success ? 'Risultati locali trovati.' : 'Nessun risultato affidabile trovato.';
let final_reply = '';

if (success) {
  const lines = normalizedResults.map((result, index) => {
    const parts = [
      `${index + 1}. ${result.name}`.trim(),
      result.address ? `- ${result.address}` : '',
      result.notes ? `(${result.notes})` : '',
      result.link ? `${result.link}` : ''
    ].filter(Boolean);

    return parts.join(' ');
  });

  final_reply = `Ho trovato queste opzioni${resolved_location ? ` vicino a ${resolved_location}` : ''}:\n\n${lines.join('\n')}`;

  if (is_time_sensitive) {
    final_reply += '\n\nSe si tratta di un servizio sensibile all’orario, ti consiglio comunque una verifica rapida prima di metterti in viaggio.';
  }
} else {
  final_reply = is_time_sensitive
    ? `Non riesco a verificare con certezza un risultato aggiornato${resolved_location ? ` per ${resolved_location}` : ''} in questo momento. Se vuoi, dimmi una zona più precisa e provo una ricerca più mirata.`
    : `Non ho trovato un risultato abbastanza chiaro${resolved_location ? ` per ${resolved_location}` : ''}. Se vuoi, dimmi una zona o una città più precisa e riprovo.`;
}

return [{
  json: {
    ...meta,
    success,
    code,
    message,
    final_reply,
    results: normalizedResults
  }
}];

const input = $json || {};

return [{
  json: {
    success: Boolean(input.success),
    final_reply: input.final_reply || 'Ho completato la ricerca.',
    query_type: input.query_type || '',
    resolved_location: input.resolved_location || '',
    result_count: Array.isArray(input.results) ? input.results.length : 0,
    results: Array.isArray(input.results) ? input.results.slice(0, 3) : []
  }
}];
